import{_ as i,W as s,X as n,Y as o,Z as e,$ as a,a1 as _,a2 as l,a0 as p,C as c}from"./framework-91490e6a.js";const r="/assets/images/RAS_in_Shanghai.jpeg",m="/assets/images/RAS_Raychell.jpg",u={},S=e("p",null,"在很久之前就听闻，在三月下旬，RAS 会在台北和上海开亚巡。作为 BanGDream 企划在中国第一次开单独 Live，而且正好是上海，这下就不得不去了。",-1),R=e("figure",null,[e("img",{src:r,alt:"家门口的现地",tabindex:"0",loading:"lazy"}),e("figcaption",null,"家门口的现地")],-1),d=e("p",null,"先说说 RAS，我是 19 年入的 BanGDream，当时正好离 RAS 从 THE THIRD（仮）变成 Raise A Suilen 很近，所以后来也很快地看到了 RAS 银河战舰般的水平。Bushiroad 决定让 RAS 先开海外巡估计也是出于这个原因吧。",-1),h=p('<p>拜托，我们是摇滚乐队，你开在看歌剧的剧院是闹哪出？</p><p>而且宛平剧院就在宛平南路 600 号旁边，因此我们就有了独特的「病 T」——「宛平南路 600 号（旁宛平剧院）出院留念」。</p><p>选在宛平剧院也导致了，总座位数特别少，感觉海日是完全低估了国内粉丝的热情，尤其是在 ylgo 特别多的现在。票价分为普席 ¥780，VIP 席 ¥980，SVIP 席 ¥1280，其中普席坐在二楼，而二楼会有铁窗泪和遮视野，总之体验不会很好。更幽默的是，海日的老头还直接当起了官方黄牛，在 day1 卖 ¥780 的山顶余票不说，在开场之后，还以 ¥500 的价格卖起了一楼的站票。</p><p>这个操作就非常迷惑了。首先是你在开演时间后，无故额外加票，而且是 ¥500 的，一楼的票。你这让抢普席 ¥780 票的人怎么想？这自然会引发众愤了。这也就导致两天演出结束后，全场都在大喊「はい日、サビ！」，第二天甚至还喊了「500，站票！」</p><p>而且，VIP 和 SVIP 的特典是见送会 <em>（SVIP 还有个印刷传单，那个我都不想提了）</em>，先不提台北场有亲签，你海日见送会一直在赶人，会在后面推你，最后估计是 1s 都没有，根本来不及见面和说话。。。</p><p>——好像聊海日聊的有点多了，不过大家确实也很愤怒，海日都被迫关评论区装死了。</p><figure><img src="'+m+'" alt="Raychell 在小红书发的返图" tabindex="0" loading="lazy"><figcaption>Raychell 在小红书发的返图</figcaption></figure><p>那么接下来谈谈演出。首先，虽然上面我对海日将公演场所选在宛平剧院是不赞成的，但是演出之后我与宛平剧院和解了。宛平剧院虽然是剧院，但是音响效果也并不糟糕，而且每个人都离舞台更近了，虽然我是第 9 排，但是我能看到第 1 排的人的位置，简直就是贴着舞台了 <em>（甚至有人说第一排都能看到 reo 的安全裤了）</em>。而且一开始我们以为不能站，但是实际上最后大家都站起来了，所以宛平剧院其实可以算是一种带固定席位的 LiveHouse 了。</p><p>再谈谈演出。首先 RAS 的歌都非常爽，大姐头的嗓音非常有贯穿力，而且 RAS 比较独特的是，作为唯一一个带 DJ 位的真人乐队，编曲中也留了很多适合应援的地方，基本上每首歌都能爽爽喊叫，而且还有很多段是摇头和跳跃，感觉人都要起飞了。当然这也是有代价的——第二天起床后全身酸痛。</p><p>有些小插曲。在我从 TPY 坐地铁回龙华中路的时候，遇到了一个老哥，看着也是很内向的，结果最后发现他的座位就在我右手边，最终一开唱，我们都应援地非常疯癫。然后是另一位我左手边的老哥，彩排时他还是地藏，但是正式演出后，虽然能够明显看出他并不懂怎么应援，但是他也非常投入地有样学样了。还有一个是群聊里的「无料姐」，她让大家不要当「疯狗」应援，结果最后坐她旁边的群友也指出，她最后被 RAS 感化了，也玩得很疯。</p><p>顺便一提，在演出最后，她们走到右边台子来致谢时，Raychell 还和我目光对视比心了。</p><p>总而言之，虽然到现在也没发合照的海日是 SB 的，但是 RAS 真的是银河战舰，歌声真的深入人心，甚至都感化了不懂应援的人，也正如那句话所说的吧，「私たちの音楽は、世界へと憑依する」！！！！！</p>',12);function g(A,f){const t=c("RouterLink");return s(),n("div",null,[S,R,o(" more "),d,e("p",null,[a("但是，居然让海日来主催了这次活动。海日之前风评就不好，首先是经典的 "),_(t,{to:"/posts/Scribble/aiaiFMT.html"},{default:l(()=>[a("i83 Fan Meeting")]),_:1}),a(" 的 13 排 VIP 席 2 排普席的经典恰米操作（VIP 票价 ¥1080）。然后是三森演唱会没开场贩。不过这次海日直接一开始就给我们整了个大的——它居然把公演场所定在了宛平剧院！！！")]),h])}const y=i(u,[["render",g],["__file","Raise_A_Suilen_Asia_Tour_2024_in_Shanghai.html.vue"]]);export{y as default};
